## Task 5: GraphExpandRetriever

        // Create graph edge: A --depends_on--> B
        use crate::traits::GraphStore;
        store.relate(&ea.id, "depends_on", &eb.id, None).await.unwrap();

        // Filler
        for i in 0..8 {
            let mut f = KnowledgeEntry::new(format!("filler-{i}"), "proj".into(), "v1".into())
                .with_embedding(next_emb());
            f.entry_status = EntryStatus::Merged;
            store.insert(&f).await.unwrap();
        }

        let graph = Arc::new(store.clone()) as Arc<dyn GraphStore>;
        let retriever = GraphExpandRetriever::new(store.clone(), engine, graph, 0.3);
        assert_eq!(retriever.name(), "graph_expand");

        let opts = RetrievalOpts { limit: 5, expand_graph: true, graph_depth: 1, ..Default::default() };
        let result = retriever.retrieve("auth query", "proj", &opts).await.unwrap();

        assert_eq!(result.metrics.retriever_name, "graph_expand");
        // Graph expansion should have found at least some neighbors
        // (HNSW may find both entries anyway via vector search, but graph_expanded count
        // should reflect edges traversed that added new entries)
        assert!(result.results.len() >= 2, "Expected at least 2 results, got {}", result.results.len());
    }

